const OWNER_TASK_HORIZON_HOURS = {
  "Customer Success": 4,
  Support: 8,
  Finance: 24,
  "Executive Sponsor": 12,
  Legal: 24
};

const DEFAULT_TASK_HORIZON_HOURS = 24;

function replaceByRequestId(collection, requestId, records) {
  const existing = collection ?? [];
  return existing.filter((item) => item.requestId !== requestId).concat(records);
}

function addHours(iso, hours) {
  const base = new Date(iso);
  base.setUTCHours(base.getUTCHours() + hours);
  return base.toISOString();
}

// Implement the rescue workflow. Connect via src/db.mjs, read raw account
// facts, derive the answer per ../RULES.md, and PERSIST workflow_state,
// owner_tasks, customer_messages, audit_events back to the live database.
import { withDb } from "./db.mjs";
import { RULES, qualifies, ownersOf, signalsOf } from "./derive.mjs";

function normalizeFacts(accountDoc) {
  return {
    account: {
      accountId: accountDoc._id,
      name: accountDoc.name,
      tier: accountDoc.tier,
      region: accountDoc.region
    },
    contract: accountDoc.contract,
    contacts: accountDoc.contacts,
    invoices: accountDoc.invoices,
    shipments: accountDoc.shipments,
    regulatoryFlags: accountDoc.regulatoryFlags,
    supportCases: accountDoc.supportCases,
    usage: accountDoc.usage
  };
}

function dueAt1600Utc(now) {
  const d = new Date(now);
  d.setUTCHours(16, 0, 0, 0);
  return d.toISOString();
}

export async function run(now = "2026-06-18T12:00:00.000Z") {
  return withDb(async (db) => {
    const account = await db.collection("accounts").findOne({});
    if (!account) {
      throw new Error("No account found in live database.");
    }

    const facts = normalizeFacts(account);
    const isQualifying = qualifies(facts, now);
    const signalNames = signalsOf(facts, now);
    const owners = isQualifying ? ownersOf(facts, now) : [];
    const status = isQualifying ? RULES.escalationStatus : RULES.monitorStatus;
    const riskSummary = `${signalNames.length} signals: ${signalNames.join(", ")}`;
    const nextStep = isQualifying ? `${owners[0]} recovery review by 16:00` : "Continue standard monitoring.";
    const messageBody = isQualifying
      ? "We identified multiple active risks affecting your account and are coordinating a recovery review to address billing, delivery, support, and usage changes. We will keep you informed as the team works through the next steps."
      : "We reviewed your account and do not see an escalation trigger right now. We will continue standard monitoring and will notify you if the situation changes.";
    const auditBody = isQualifying
      ? `Customer-visible escalation update recorded for ${facts.account.name}.`
      : `Customer-visible monitoring update recorded for ${facts.account.name}.`;

    await db.collection("workflow_state").deleteMany({});
    await db.collection("owner_tasks").deleteMany({});
    await db.collection("customer_messages").deleteMany({});
    await db.collection("audit_events").deleteMany({});

    await db.collection("workflow_state").insertOne({
      status,
      next_step: nextStep,
      risk_summary: riskSummary
    });

    if (isQualifying) {
      const due_at = dueAt1600Utc(now);
      await db.collection("owner_tasks").insertMany(
        owners.map((owner_group) => ({
          owner_group,
          title: `${owner_group} recovery review`,
          due_at,
          status: "open"
        }))
      );
    }

    await db.collection("customer_messages").insertOne({
      body: messageBody
    });

    await db.collection("audit_events").insertOne({
      body: auditBody,
      customer_visible: true
    });

    return {
      status,
      owners,
      riskSummary,
      nextStep
    };
  });
}

if (import.meta.url === `file://${process.argv[1]}`) {
  run().then(() => console.log("workflow done")).catch((e) => { console.error(e); process.exit(1); });
}

import { buildPortalView } from "./portal-view.mjs";

const CUSTOMER_SAFE_STATUS = "At-risk escalation active with executive recovery owner routing and customer-visible audit history.";

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests?.[0];
  if (!request) {
    return buildPortalView(db);
  }

  const account = (db.accounts || []).find((item) => item._id === request.accountId);
  const activities = (db.activities || [])
    .filter((item) => item.subjectId === request._id)
    .slice()
    .sort((left, right) => left.occurredAt.localeCompare(right.occurredAt));
  const riskSignals = (request.riskSignals || []).map((item) => ({ ...item }));
  const timestamp = new Date(now).toISOString();

  const customerMessage = {
    _id: `customer-message-${request._id}`,
    requestId: request._id,
    accountId: request.accountId,
    audience: "customer",
    visibility: "customer-safe",
    body: "We have activated an at-risk escalation for your delayed order. Recovery work is underway, and portal updates will stay customer-safe and visible here.",
    customerVisible: true,
    createdAt: timestamp,
    updatedAt: timestamp
  };

  const auditEvent = {
