        timelineActivityIds: activities.map((item) => item._id),
        auditEventId: auditEvent._id
      }
    },
    auditTimeline: [
      ...activities.map((item) => ({
        kind: "activity",
        activityId: item._id,
        occurredAt: item.occurredAt,
